function alienOrder(words) {
  const adj = {};
  const inDegree = {};

  for (const word of words) {
    for (const char of word) {
      inDegree[char] = 0;
      adj[char] = [];
    }
  }

  for (let i = 0; i < words.length - 1; i++) {
    const w1 = words[i];
    const w2 = words[i+1];
    const minLen = Math.min(w1.length, w2.length);

    if (w1.length > w2.length && w1.slice(0, minLen) === w2.slice(0, minLen)) return "";

    for (let j = 0; j < minLen; j++) {
      if (w1[j] !== w2[j]) {
        adj[w1[j]].push(w2[j]);
        inDegree[w2[j]]++;
        break;
      }
    }
  }

  const queue = [];
  for (const char in inDegree) {
    if (inDegree[char] === 0) queue.push(char);
  }

  let result = "";
  while (queue.length > 0) {
    const char = queue.shift();
    result += char;
    for (const neighbor of adj[char]) {
      inDegree[neighbor]--;
      if (inDegree[neighbor] === 0) queue.push(neighbor);
    }
  }

  return result.length === Object.keys(inDegree).length ? result : "";
}

