solution:
function cloneGraph(node) {
  if (!node) return null;
  const map = new Map();

  function dfs(n) {
    if (map.has(n)) return map.get(n);

    const clone = { val: n.val, neighbors: [] };
    map.set(n, clone);

    for (const neighbor of n.neighbors) {
      clone.neighbors.push(dfs(neighbor));
    }

    return clone;
  }

  return dfs(node);
}

